sql:
SELECT sms_date, sms_count
FROM sms
WHERE sms_date = '2022-02-15';

SELECT COUNT(customer_id) AS churn_count
FROM churn
WHERE reason = 'unsatisfied with service';

SELECT AVG(f.rating) AS average_rating
FROM churn c
JOIN feedback f ON c.customer_id = f.customer_id;

SELECT AVG(c.tenure) AS average_tenure
FROM customers c
INNER JOIN churn ch ON c.customer_id = ch.customer_id;

